def validate(model, valid_loader):
    model.eval()
    losses = []
    with torch.no_grad():
        for xb, yb in valid_loader:
            logits = model(xb.to(device))
            loss = criterion(logits, yb.to(device))
            losses.append(loss.item())
    return sum(losses) / len(losses)

